# Clean A* Pathfinding Implementation

After deobfuscating the code, I can see it implements the **A* pathfinding algorithm** on a 2D grid with diagonal movement support. Here's a clean rewrite:

```javascript
// --- Configuration ---
const GRID_WIDTH = 20;
const GRID_HEIGHT = 15;
const config = {
  heuristic: 'manhattan',    // 'manhattan' or 'euclidean'
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  wallProbability: 0.25,
};

// --- Grid Generation ---
const grid = [];
for (let y = 0; y < GRID_HEIGHT; y++) {
  grid[y] = [];
  for (let x = 0; x < GRID_WIDTH; x++) {
    grid[y][x] = Math.random() < config.wallProbability ? 1 : 0;
  }
}

const startNode = { x: 0, y: 0 };
const goalNode = { x: GRID_WIDTH - 1, y: GRID_HEIGHT - 1 };

// Ensure start and goal are walkable
grid[startNode.y][startNode.x] = 0;
grid[goalNode.y][goalNode.x] = 0;

// --- Heuristic Function ---
function heuristic(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);
  if (config.heuristic === 'manhattan') {
    return dx + dy;
  }
  return Math.sqrt(dx * dx + dy * dy);
}

// --- Get Walkable Neighbors ---
function getNeighbors(node) {
  const neighbors = [];
  const directions = [
    { dx:  0, dy: -1, cost: config.straightCost },  // up
    { dx:  0, dy:  1, cost: config.straightCost },  // down
    { dx: -1, dy:  0, cost: config.straightCost },  // left
    { dx:  1, dy:  0, cost: config.straightCost },  // right
    { dx: -1, dy: -1, cost: config.diagonalCost },  // up-left
    { dx:  1, dy: -1, cost: config.diagonalCost },  // up-right
    { dx: -1, dy:  1, cost: config.diagonalCost },  // down-left
    { dx:  1, dy:  1, cost: config.diagonalCost },  // down-right
  ];

  for (const dir of directions) {
    const nx = node.x + dir.dx;
    const ny = node.y + dir.dy;
    if (nx >= 0 && nx < GRID_WIDTH && ny >= 0 && ny < GRID_HEIGHT && grid[ny][nx] === 0) {
      neighbors.push({ x: nx, y: ny, moveCost: dir.cost });
    }
  }
  return neighbors;
}

// --- Node Key for Map Lookups ---
function nodeKey(node) {
  return node.x + ',' + node.y;
}

// --- A* Pathfinding ---
function findPath(start, goal) {
  const startKey = nodeKey(start);

  const openSet = {};          // nodes to explore: key -> node
  const closedSet = {};        // already explored: key -> node
  const cameFrom = {};         // key -> parent key
  const gScore = {};           // key -> cost from start
  const fScore = {};           // key -> gScore + heuristic

  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = heuristic(start, goal);

  let iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
    iterations++;

    // Find the open node with the lowest fScore
    let currentKey = null;
    let lowestF = Infinity;
    for (const key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    const currentNode = openSet[currentKey];

    // Check if we've reached the goal
    if (currentNode.x === goal.x && currentNode.y === goal.y) {
      const path = [currentNode];
      let traceKey = currentKey;
      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        const node = openSet[traceKey] || closedSet[traceKey] || {
          x: parseInt(traceKey),
          y: parseInt(traceKey.split(',')[1]),
        };
        path.push(node);
      }
      return { path, cost: gScore[currentKey], iterations };
    }

    // Move current node from open to closed
    delete openSet[currentKey];
    closedSet[currentKey] = currentNode;

    // Explore neighbors
    const neighbors = getNeighbors(currentNode);
    for (const neighbor of neighbors) {
      const neighborKey = nodeKey(neighbor);
      if (closedSet[neighborKey]) continue;

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristic(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  // No path found
  return { path: [], cost: Infinity, iterations };
}

// --- Run ---
const result = findPath(startNode, goalNode);
console.log(
  'Path length:', result.path.length,
  'Cost:', result.cost,
  'Iterations:', result.iterations
);
```

## Key observations from the deobfuscated code:

1. **Algorithm**: Classic **A\*** with open/closed sets stored as objects keyed by `"x,y"` strings
2. **Grid**: Random walls generated with 25% probability on a 20×15 grid
3. **Movement**: 8-directional — cardinal directions cost 1, diagonals cost 1.414 (≈√2)
4. **Heuristic**: Configurable between Manhattan and Euclidean distance
5. **Termination**: Stops when the goal is reached or after 1000 iterations
6. **Path reconstruction**: Traces back through a `cameFrom` map from goal to start
